cat > /tmp/grant_all_access.mjs <<'EOF'
const BASE = "https://data.designflow.app";

async function login() {
  const r = await fetch(`${BASE}/auth/login`, {
    method: "POST", headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ email: "svc@popcre.com", password: "CMEXRBT2myN4qPZchdtvevHe" })
  });
  const j = await r.json();
  if (!j.data?.access_token) throw new Error("login failed: " + JSON.stringify(j));
  return j.data.access_token;
}

async function api(token, path, method = "GET", body) {
  const r = await fetch(`${BASE}${path}`, {
    method,
    headers: { "Authorization": `Bearer ${token}`, "Content-Type": "application/json" },
    body: body ? JSON.stringify(body) : undefined
  });
  const text = await r.text();
  let j; try { j = JSON.parse(text); } catch { j = text; }
  if (!r.ok) throw new Error(`${method} ${path} -> ${r.status}: ${text}`);
  return j;
}

const businessCollections = [
  "buyer","checklist_item","crm_ai_model_config","crm_department","crm_email_message",
  "crm_ignore_rule","crm_licensor_approval_thread","crm_meeting_note","crm_meeting_note_attendee",
  "crm_note","crm_opportunity","crm_task","design","design_collection","factory","licensor",
  "order","pm_saved_view","product","product_activity","product_assignee","product_field",
  "product_file","product_link","product_sample","product_submission","product_tag",
  "product_time_entry","product_type","product_update","project","property","retailer",
  "revision_request","season","stage","stage_history","subtask"
];

// system collections: action list per collection
const systemGrants = {
  "directus_files":         ["create","read","update","delete"],
  "directus_users":         ["read"],
  "directus_roles":         ["read"],
  "directus_presets":       ["create","read","update","delete"],
  "directus_comments":      ["create","read","update","delete"],
  "directus_notifications": ["create","read","update","delete"],
  "directus_shares":        ["create","read","update","delete"],
  "directus_activity":      ["read"],
  "directus_dashboards":    ["read"],
  "directus_panels":        ["read"],
  "directus_flows":         ["read"],
};

const token = await login();

// 1. Create the policy
const pol = await api(token, "/policies", "POST", {
  name: "All Access (temp)",
  icon: "lock_open",
  description: "Temporary: full access to all data for all app users during setup. Remove/replace when gating is introduced.",
  app_access: true,
  admin_access: false
});
const policyId = pol.data.id;
console.log("Created policy:", policyId);

// 2. Build permission rows
const perms = [];
for (const c of businessCollections) {
  for (const action of ["create","read","update","delete"]) {
    perms.push({ policy: policyId, collection: c, action, fields: ["*"], permissions: {}, validation: {} });
  }
}
for (const [c, actions] of Object.entries(systemGrants)) {
  for (const action of actions) {
    perms.push({ policy: policyId, collection: c, action, fields: ["*"], permissions: {}, validation: {} });
  }
}
console.log("Creating", perms.length, "permission rows...");
await api(token, "/permissions", "POST", perms);
console.log("Permissions created.");

// 3. Attach policy to the 5 app roles
const appRoles = {
  "Vendor":    "5a6ae108-85d8-4204-8e84-32949046e6c9",
  "Designer":  "7c7299c9-bf6c-44f6-b952-b6983a3ca6e8",
  "Licensing": "91f1d91d-3957-40aa-8172-0f581fda34ea",
  "Sales":     "a0ab4347-e023-4f50-b7aa-136b3ebb35c7",
  "Viewer":    "fd4e0ce0-9b6a-44b3-a243-5869a3856552"
};
const accessRows = Object.entries(appRoles).map(([name, role]) => ({ role, policy: policyId }));
await api(token, "/access", "POST", accessRows);
console.log("Attached policy to roles:", Object.keys(appRoles).join(", "));
console.log("DONE. policyId =", policyId);
EOF
